export function scale(image: string[], scaleFactor: number): string[] {
  if (scaleFactor === 1) {
    return [...image];
  }
  if (image.length === 0) {
    return [];
  }

  // First: horizontal scaling - duplicate each character
  const horizontallyScaled = image.map((line) =>
    line
      .split("")
      .map((char) => char.repeat(scaleFactor))
      .join("")
  );

  // Second: vertical scaling - duplicate each line
  const result: string[] = [];
  for (const line of horizontallyScaled) {
    for (let i = 0; i < scaleFactor; i++) {
      result.push(line);
    }
  }
  return result;
}

